let _icons = {};
let count = 0;
/** Add icons to library to be used for rendering using name.
This needs to be done lonly once */
const add = icons => {
  _icons = {
    ..._icons,
    ...icons
  };
};
const get = name => {
  count += 1;
  return {
    icon: _icons[name],
    count
  };
};

export { add, get };
